import React, { useState, useEffect } from 'react';
import { GripVertical, Plus, Trash2, MapPin, Navigation, MoreHorizontal, Calendar, CheckCircle2, Loader2, Sparkles, RefreshCcw } from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

interface Activity {
  id: string;
  time: string;
  title: string;
  category: string;
  duration: string;
}

const TripPreview: React.FC = () => {
  const [activeDay, setActiveDay] = useState(1);
  const [itinerary, setItinerary] = useState<Activity[]>([
    { id: '1', time: "09:00 AM", title: "Breakfast at Tsujiki", category: "Food", duration: "1h 30m" },
    { id: '2', time: "11:00 AM", title: "TeamLab Borderless", category: "Art", duration: "3h" },
    { id: '3', time: "02:30 PM", title: "Imperial Palace Garden", category: "Nature", duration: "2h" },
    { id: '4', time: "05:00 PM", title: "Shopping in Ginza", category: "Shopping", duration: "2h" },
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const [query, setQuery] = useState('');

  // Listen for the hero event
  useEffect(() => {
    const handlePlanEvent = (e: any) => {
      if (e.detail) {
        setQuery(e.detail);
        generateAITrip(e.detail);
      }
    };
    window.addEventListener('start-plan', handlePlanEvent);
    return () => window.removeEventListener('start-plan', handlePlanEvent);
  }, []);

  const generateAITrip = async (prompt: string) => {
    if (!prompt) return;
    setIsLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Create a one-day travel itinerary for: ${prompt}. Return exactly 4 activities in a logical time sequence.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                time: { type: Type.STRING },
                title: { type: Type.STRING },
                category: { type: Type.STRING },
                duration: { type: Type.STRING }
              },
              required: ["time", "title", "category", "duration"]
            }
          }
        },
      });

      const data = JSON.parse(response.text);
      setItinerary(data.map((item: any, idx: number) => ({ ...item, id: Math.random().toString(36).substr(2, 9) })));
    } catch (error) {
      console.error("AI Generation failed:", error);
      alert("Something went wrong with the AI co-pilot. Using backup itinerary.");
    } finally {
      setIsLoading(false);
    }
  };

  const removeActivity = (id: string) => {
    setItinerary(prev => prev.filter(item => item.id !== id));
  };

  const addActivity = () => {
    const newAct = {
      id: Math.random().toString(36).substr(2, 9),
      time: "08:00 PM",
      title: "New Custom Location",
      category: "Custom",
      duration: "1h"
    };
    setItinerary([...itinerary, newAct]);
  };

  return (
    <section id="preview" className="py-24 bg-slate-50 overflow-hidden scroll-mt-20">
      <div className="container mx-auto px-4">
        <div className="flex flex-col lg:flex-row gap-12 items-center">
          <div className="lg:w-1/3 text-left">
            <h3 className="text-3xl md:text-5xl font-extrabold text-slate-900 mb-6">Built for precision</h3>
            <p className="text-slate-600 text-lg mb-8 leading-relaxed">
              Managing a 10-day trip shouldn't feel like a part-time job. Our drag-and-drop interface makes refining your AI-generated draft as easy as playing a game.
            </p>

            <div className="bg-indigo-600 rounded-2xl p-6 text-white mb-8 shadow-xl">
              <div className="flex items-center gap-2 mb-4">
                <Sparkles className="w-5 h-5 text-indigo-200" />
                <h4 className="font-bold">AI Command Center</h4>
              </div>
              <input 
                type="text" 
                placeholder="Try: 'Make it more romantic' or 'Add a sushi spot'"
                className="w-full bg-indigo-700/50 border border-indigo-400/30 rounded-lg p-3 text-sm placeholder:text-indigo-300 focus:outline-none focus:ring-2 focus:ring-white/50 mb-3"
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && generateAITrip(query)}
              />
              <button 
                onClick={() => generateAITrip(query)}
                disabled={isLoading}
                className="w-full py-2 bg-white text-indigo-600 font-bold rounded-lg text-sm flex items-center justify-center gap-2 hover:bg-indigo-50 transition-colors"
              >
                {isLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <RefreshCcw className="w-4 h-4" />}
                {isLoading ? 'Co-pilot Thinking...' : 'Regenerate Day'}
              </button>
            </div>

            <div className="space-y-4">
              <div className="flex items-center gap-3 p-3 bg-white rounded-xl shadow-sm">
                <div className="w-8 h-8 bg-emerald-100 text-emerald-600 rounded-lg flex items-center justify-center">
                  <CheckCircle2 className="w-5 h-5" />
                </div>
                <span className="font-medium text-slate-700">Auto-check opening times</span>
              </div>
              <div className="flex items-center gap-3 p-3 bg-white rounded-xl shadow-sm">
                <div className="w-8 h-8 bg-blue-100 text-blue-600 rounded-lg flex items-center justify-center">
                  <Navigation className="w-5 h-5" />
                </div>
                <span className="font-medium text-slate-700">Calculate walking vs transit</span>
              </div>
            </div>
          </div>

          <div className="lg:w-2/3 w-full">
            <div className={`bg-white rounded-3xl shadow-2xl border border-slate-200 overflow-hidden flex flex-col md:flex-row h-[600px] transition-opacity duration-300 ${isLoading ? 'opacity-50' : 'opacity-100'}`}>
              {/* Sidebar */}
              <div className="w-full md:w-56 border-r border-slate-100 bg-slate-50 p-6">
                <div className="flex items-center justify-between mb-8">
                  <h4 className="font-bold text-slate-900">Itinerary</h4>
                  <button className="p-1 hover:bg-slate-200 rounded transition-colors">
                    <Calendar className="w-4 h-4 text-slate-500" />
                  </button>
                </div>
                <div className="space-y-2">
                  {[1, 2, 3, 4, 5].map(day => (
                    <button 
                      key={day}
                      onClick={() => setActiveDay(day)}
                      className={`w-full text-left px-4 py-3 rounded-xl text-sm font-bold transition-all ${
                        activeDay === day 
                        ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' 
                        : 'text-slate-500 hover:bg-slate-200/50'
                      }`}
                    >
                      Day {day}
                    </button>
