      case '#terms': return <TermsOfServicePage />;
      case '#contact': return <ContactPage />;
      case '#home':
      default:
        return <LandingPage />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar />
      <main className="flex-grow">
        {renderView()}
      </main>
      <Footer />
    </div>
  );
};

