import React, { useState, useEffect } from 'react';
import { 
  GripVertical, Plus, Trash2, MapPin, Navigation, 
  MoreHorizontal, Calendar, CheckCircle2, Loader2, 
  Sparkles, RefreshCcw, Send, ArrowLeft 
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

interface Activity {
  id: string;
  time: string;
  title: string;
  category: string;
  duration: string;
}

const PlannerPage: React.FC = () => {
  const [activeDay, setActiveDay] = useState(1);
  const [itinerary, setItinerary] = useState<Activity[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [query, setQuery] = useState('');
  const [destinationName, setDestinationName] = useState('New Adventure');

  useEffect(() => {
    // Read query from URL hash
    const params = new URLSearchParams(window.location.hash.split('?')[1]);
    const q = params.get('q');
    if (q) {
      setQuery(q);
      setDestinationName(q.split(' ')[0] || q);
      generateAITrip(q);
    }
  }, []);

  const generateAITrip = async (prompt: string) => {
    if (!prompt) return;
    setIsLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Create a one-day travel itinerary for: ${prompt}. Return exactly 4 activities in a logical time sequence.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                time: { type: Type.STRING, description: "Time of day like '09:00 AM'" },
                title: { type: Type.STRING, description: "Name of the place or activity" },
                category: { type: Type.STRING, description: "Category like 'Food', 'Art', 'Nature'" },
                duration: { type: Type.STRING, description: "How long to spend there like '2h'" }
              },
              required: ["time", "title", "category", "duration"]
            }
          }
        },
      });

      const text = response.text;
      const data = JSON.parse(text);
      setItinerary(data.map((item: any) => ({ ...item, id: Math.random().toString(36).substr(2, 9) })));
      setDestinationName(prompt.split('in').pop()?.trim() || prompt.split(' ').slice(0, 2).join(' '));
    } catch (error) {
      console.error("AI Generation failed:", error);
      alert("AI Co-pilot encountered a hitch. Please check your prompt and try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const removeActivity = (id: string) => {
    setItinerary(prev => prev.filter(item => item.id !== id));
  };

  const addActivity = () => {
    const newAct = {
      id: Math.random().toString(36).substr(2, 9),
      time: "08:00 PM",
      title: "New Custom Location",
      category: "Custom",
      duration: "1h"
    };
    setItinerary([...itinerary, newAct]);
  };

  return (
    <div className="pt-24 min-h-screen bg-slate-50 flex flex-col">
      {/* Header bar */}
      <div className="bg-white border-b border-slate-200 sticky top-16 z-30 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center gap-4">
          <button onClick={() => window.location.hash = '#home'} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
            <ArrowLeft className="w-5 h-5 text-slate-500" />
          </button>
          <div>
            <h1 className="text-xl font-extrabold text-slate-900 flex items-center gap-2">
              <MapPin className="w-5 h-5 text-indigo-600" />
              {destinationName}
            </h1>
            <p className="text-xs text-slate-500 font-medium">Your Personal Trip Draft</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className="relative group flex-grow md:w-64">
            <input 
              type="text" 
              placeholder="Refine trip..."
              className="w-full pl-4 pr-10 py-2 bg-slate-100 border border-transparent focus:bg-white focus:border-indigo-500 rounded-xl text-sm transition-all"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && generateAITrip(query)}
            />
            <button 
              onClick={() => generateAITrip(query)}
              className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400 hover:text-indigo-600"
            >
              <Send className="w-4 h-4" />
            </button>
          </div>
          <button 
            onClick={() => alert("Itinerary saved to your dashboard!")}
            className="px-4 py-2 bg-indigo-600 text-white text-sm font-bold rounded-xl shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all"
          >
            Save Trip
          </button>
        </div>
      </div>

      <div className="flex-grow flex flex-col lg:flex-row container mx-auto px-4 py-8 gap-8">
        {/* Workspace Sidebar */}
        <aside className="lg:w-1/4 space-y-6">
          <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
            <h4 className="font-bold text-slate-900 mb-6 flex items-center justify-between">
              Itinerary
              <Calendar className="w-4 h-4 text-slate-400" />
            </h4>
            <div className="space-y-2">
              {[1, 2, 3].map(day => (
                <button 
                  key={day}
                  onClick={() => setActiveDay(day)}
                  className={`w-full text-left px-4 py-3 rounded-xl text-sm font-bold transition-all flex items-center justify-between ${
                    activeDay === day 
                    ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' 
                    : 'text-slate-600 hover:bg-slate-100'
                  }`}
                >
                  Day {day}
                  {day === 1 && <span className="text-[10px] bg-white/20 px-1.5 py-0.5 rounded uppercase">Active</span>}
                </button>
              ))}
              <button className="w-full text-left px-4 py-3 rounded-xl text-sm font-bold text-indigo-600 flex items-center gap-2 hover:bg-indigo-50 transition-colors">
                <Plus className="w-4 h-4" /> Add Day
              </button>
            </div>
          </div>

          <div className="bg-indigo-600 rounded-3xl p-6 text-white shadow-xl shadow-indigo-100">
            <div className="flex items-center gap-2 mb-4">
              <Sparkles className="w-5 h-5 text-indigo-200" />
              <h4 className="font-bold">AI Command</h4>
            </div>
            <p className="text-xs text-indigo-100 mb-4 leading-relaxed">Tell the co-pilot what to change about this specific day.</p>
            <button 
              onClick={() => generateAITrip(`Make the day for ${query} more budget friendly`)}
              className="w-full py-2 bg-white/10 hover:bg-white/20 border border-white/20 rounded-lg text-xs font-bold transition-all mb-2"
            >
              "Make it budget-friendly"
            </button>
            <button 
              onClick={() => generateAITrip(`Add more nature spots to this day in ${query}`)}
              className="w-full py-2 bg-white/10 hover:bg-white/20 border border-white/20 rounded-lg text-xs font-bold transition-all"
            >
              "Add more nature"
            </button>
          </div>
        </aside>

        {/* Main Canvas */}
        <div className="lg:w-3/4 space-y-6">
          <div className={`bg-white rounded-[2.5rem] shadow-xl border border-slate-200 min-h-[600px] flex flex-col transition-all duration-300 ${isLoading ? 'opacity-60 blur-[1px]' : ''}`}>
            <div className="p-8 border-b border-slate-100 flex items-center justify-between">
              <div className="text-left">
                <h2 className="text-2xl font-black text-slate-900">Day {activeDay} Overview</h2>
                <p className="text-slate-500 text-sm">Review and refine your co-pilot's suggestions.</p>
              </div>
              <button 
                onClick={() => generateAITrip(query)}
                disabled={isLoading}
                className="flex items-center gap-2 px-4 py-2 bg-slate-100 hover:bg-slate-200 rounded-xl text-sm font-bold text-slate-700 transition-all"
              >
                {isLoading ? <Loader2 className="w-4 h-4 animate-spin text-indigo-600" /> : <RefreshCcw className="w-4 h-4" />}
                Regenerate Day
              </button>
            </div>

            <div className="p-8 space-y-6 overflow-y-auto">
              {isLoading && itinerary.length === 0 && (
                <div className="flex flex-col items-center justify-center py-20 text-center">
                  <div className="w-16 h-16 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center mb-6 animate-pulse">
                    <Sparkles className="w-8 h-8" />
                  </div>
                  <h3 className="text-xl font-bold text-slate-900 mb-2">Co-pilot is drafting...</h3>
                  <p className="text-slate-500 max-w-xs mx-auto">Analyzing routes, checking opening hours, and picking the best spots just for you.</p>
                </div>
              )}

              {itinerary.length > 0 ? (
                itinerary.map((item, idx) => (
                  <div key={item.id} className="group relative bg-white border border-slate-200 hover:border-indigo-400 p-6 rounded-3xl flex items-center gap-6 transition-all hover:shadow-lg">
                    <div className="cursor-grab text-slate-300 hover:text-slate-400 shrink-0">
                      <GripVertical className="w-5 h-5" />
                    </div>
                    <div className="w-20 shrink-0 flex flex-col items-center">
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Arrive</span>
                      <span className="text-sm font-black text-indigo-600">{item.time}</span>
                    </div>
                    <div className="h-12 w-px bg-slate-100 shrink-0" />
                    <div className="flex-1 text-left">
                      <h4 className="font-bold text-slate-900 text-lg group-hover:text-indigo-600 transition-colors">{item.title}</h4>
                      <div className="flex items-center gap-3 mt-1.5">
                        <span className="text-[10px] px-2.5 py-1 rounded-full bg-slate-100 text-slate-600 font-bold uppercase tracking-tight">{item.category}</span>
                        <span className="text-[10px] text-slate-400 font-bold flex items-center gap-1">
                          <Clock className="w-3 h-3" /> {item.duration}
                        </span>
                      </div>
                    </div>
                    <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button 
                        onClick={() => removeActivity(item.id)}
                        className="p-3 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-2xl transition-all"
                      >
                        <Trash2 className="w-5 h-5" />
                      </button>
                      <button className="p-3 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-2xl transition-all">
                        <MoreHorizontal className="w-5 h-5" />
                      </button>
                    </div>
                  </div>
                ))
              ) : !isLoading && (
                <div className="flex flex-col items-center justify-center py-20 text-center opacity-40">
                  <Navigation className="w-12 h-12 mb-4" />
                  <p className="font-bold">Your itinerary is empty.</p>
                  <p className="text-sm">Use the search bar above to start planning.</p>
                </div>
              )}

              {itinerary.length > 0 && (
                <button 
                  onClick={addActivity}
                  className="w-full py-6 border-2 border-dashed border-slate-200 rounded-[2rem] text-slate-400 font-bold text-sm hover:border-indigo-300 hover:text-indigo-600 hover:bg-indigo-50/50 transition-all flex items-center justify-center gap-2"
                >
                  <Plus className="w-5 h-5" /> Add Location to This Day
                </button>
              )}
            </div>

            <div className="mt-auto p-8 bg-slate-50 border-t border-slate-100 rounded-b-[2.5rem]">
              <div className="flex flex-col md:flex-row items-center justify-between gap-4">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center shadow-sm text-indigo-600">
                    <Navigation className="w-5 h-5" />
                  </div>
                  <div className="text-left">
