import React, { useState, useEffect } from 'react';
import { 
  GripVertical, Plus, Trash2, MapPin, Navigation, 
  MoreHorizontal, Calendar, Loader2, 
  Sparkles, RefreshCcw, Send, ArrowLeft, Clock
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { ViewType } from '../App';

interface Activity {
  id: string;
  time: string;
  title: string;
  category: string;
  duration: string;
}

interface PlannerPageProps {
  initialQuery?: string;
  navigateTo: (view: ViewType) => void;
}

const PlannerPage: React.FC<PlannerPageProps> = ({ initialQuery, navigateTo }) => {
  const [activeDay, setActiveDay] = useState(1);
  const [itinerary, setItinerary] = useState<Activity[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [query, setQuery] = useState(initialQuery || '');
  const [destinationName, setDestinationName] = useState(initialQuery || 'New Trip');

  useEffect(() => {
    if (initialQuery) {
      generateAITrip(initialQuery);
    }
  }, []);

  const generateAITrip = async (prompt: string) => {
    if (!prompt) return;
    setIsLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Create a one-day travel itinerary for: ${prompt}. Return exactly 4 activities in a logical time sequence. JSON format only.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                time: { type: Type.STRING },
                title: { type: Type.STRING },
                category: { type: Type.STRING },
                duration: { type: Type.STRING }
              },
              required: ["time", "title", "category", "duration"]
            }
          }
        },
      });

      const data = JSON.parse(response.text || '[]');
      setItinerary(data.map((item: any) => ({ ...item, id: Math.random().toString(36).substr(2, 9) })));
      setDestinationName(prompt.split('in').pop()?.trim() || prompt.split(' ').slice(0, 2).join(' '));
    } catch (error) {
      console.error("AI Generation failed:", error);
      alert("AI Co-pilot encountered an error. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const removeActivity = (id: string) => setItinerary(prev => prev.filter(item => item.id !== id));
  const addActivity = () => {
    setItinerary([...itinerary, { id: Math.random().toString(36).substr(2, 9), time: "08:00 PM", title: "Custom Stop", category: "Custom", duration: "1h" }]);
  };

  return (
    <div className="pt-24 min-h-screen bg-slate-50 dark:bg-slate-900/50 flex flex-col">
      <div className="bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 sticky top-16 z-30 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center gap-4">
          <button onClick={() => navigateTo('home')} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors outline-none">
            <ArrowLeft className="w-5 h-5 text-slate-500" />
          </button>
          <div className="text-left">
            <h1 className="text-xl font-extrabold text-slate-900 dark:text-white flex items-center gap-2 capitalize">
              <MapPin className="w-5 h-5 text-indigo-600" />
              {destinationName}
            </h1>
            <p className="text-xs text-slate-500 font-medium">Interactive Draft</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className="relative group flex-grow md:w-64">
            <input 
              type="text" 
              placeholder="Refine trip..."
              className="w-full pl-4 pr-10 py-2 bg-slate-100 dark:bg-slate-800 border border-transparent focus:bg-white dark:focus:bg-slate-700 focus:border-indigo-500 rounded-xl text-sm transition-all outline-none text-slate-900 dark:text-white"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && generateAITrip(query)}
            />
            <button onClick={() => generateAITrip(query)} className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400 hover:text-indigo-600 outline-none">
              <Send className="w-4 h-4" />
            </button>
          </div>
          <button onClick={() => alert("Trip saved!")} className="px-4 py-2 bg-indigo-600 text-white text-sm font-bold rounded-xl shadow-lg hover:bg-indigo-700 transition-all outline-none">Save</button>
        </div>
      </div>

      <div className="flex-grow flex flex-col lg:flex-row container mx-auto px-4 py-8 gap-8">
        <aside className="lg:w-1/4 space-y-6">
          <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm">
            <h4 className="font-bold text-slate-900 dark:text-white mb-6 flex items-center justify-between">Plan <Calendar className="w-4 h-4 text-slate-400" /></h4>
            <div className="space-y-2">
              {[1, 2, 3].map(day => (
                <button 
                  key={day} 
                  onClick={() => setActiveDay(day)}
                  className={`w-full text-left px-4 py-3 rounded-xl text-sm font-bold transition-all flex items-center justify-between outline-none ${
                    activeDay === day ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'
                  }`}
                >
                  Day {day}
                </button>
              ))}
            </div>
          </div>
          <div className="bg-indigo-600 rounded-3xl p-6 text-white shadow-xl">
            <h4 className="font-bold flex items-center gap-2 mb-4"><Sparkles className="w-5 h-5" /> AI Command</h4>
            <button onClick={() => generateAITrip(`Make the day for ${query} more budget friendly`)} className="w-full py-2 bg-white/10 hover:bg-white/20 border border-white/20 rounded-lg text-xs font-bold transition-all mb-2">Budget Friendly</button>
            <button onClick={() => generateAITrip(`Add nature spots to ${query}`)} className="w-full py-2 bg-white/10 hover:bg-white/20 border border-white/20 rounded-lg text-xs font-bold transition-all">Nature Focus</button>
          </div>
        </aside>

        <div className="lg:w-3/4 space-y-6">
          <div className={`bg-white dark:bg-slate-900 rounded-[2.5rem] shadow-xl border border-slate-200 dark:border-slate-800 min-h-[600px] flex flex-col transition-all duration-300 ${isLoading ? 'opacity-60 grayscale-[0.5]' : ''}`}>
            <div className="p-8 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <div className="text-left">
                <h2 className="text-2xl font-black text-slate-900 dark:text-white">Day {activeDay}</h2>
                <p className="text-slate-500 dark:text-slate-400 text-sm">Refine your itinerary below.</p>
              </div>
              <button onClick={() => generateAITrip(query)} className="flex items-center gap-2 px-4 py-2 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-xl text-sm font-bold text-slate-700 dark:text-slate-300 transition-all outline-none">
                {isLoading ? <Loader2 className="w-4 h-4 animate-spin text-indigo-600" /> : <RefreshCcw className="w-4 h-4" />}
                Refresh
              </button>
            </div>

            <div className="p-8 space-y-6 overflow-y-auto">
              {itinerary.length > 0 ? (
                itinerary.map(item => (
                  <div key={item.id} className="group relative bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 hover:border-indigo-400 p-6 rounded-3xl flex items-center gap-6 transition-all hover:shadow-lg">
                    <GripVertical className="w-5 h-5 text-slate-300 shrink-0" />
                    <div className="w-20 shrink-0 flex flex-col items-center">
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Time</span>
                      <span className="text-sm font-black text-indigo-600 dark:text-indigo-400">{item.time}</span>
                    </div>
                    <div className="flex-1 text-left">
                      <h4 className="font-bold text-slate-900 dark:text-white text-lg group-hover:text-indigo-600 transition-colors">{item.title}</h4>
                      <div className="flex items-center gap-3 mt-1.5">
                        <span className="text-[10px] px-2.5 py-1 rounded-full bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 font-bold uppercase tracking-tight">{item.category}</span>
                        <span className="text-[10px] text-slate-400 font-bold flex items-center gap-1"><Clock className="w-3 h-3" /> {item.duration}</span>
                      </div>
                    </div>
                    <button onClick={() => removeActivity(item.id)} className="p-3 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-2xl opacity-0 group-hover:opacity-100 transition-all">
                      <Trash2 className="w-5 h-5" />
                    </button>
                  </div>
                ))
              ) : !isLoading && (
                <div className="flex flex-col items-center justify-center py-20 text-center opacity-40">
                  <Navigation className="w-12 h-12 mb-4 dark:text-white" />
                  <p className="font-bold dark:text-white">Your itinerary is empty.</p>
                </div>
              )}
              {itinerary.length > 0 && (
                <button onClick={addActivity} className="w-full py-6 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-[2rem] text-slate-400 font-bold text-sm hover:border-indigo-300 hover:text-indigo-600 hover:bg-indigo-50/50 transition-all flex items-center justify-center gap-2 outline-none">
                  <Plus className="w-5 h-5" /> Add Location
                </button>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PlannerPage;

import React, { useState, useEffect } from 'react';
import LandingPage from './LandingPage';
import HowItWorksPage from './pages/HowItWorksPage';
import FeaturesPage from './pages/FeaturesPage';
import PricingPage from './pages/PricingPage';
import BlogPage from './pages/BlogPage';
import GuidebooksPage from './pages/GuidebooksPage';
import CommunityPage from './pages/CommunityPage';
import SupportPage from './pages/SupportPage';
import AboutPage from './pages/AboutPage';
import PrivacyPolicyPage from './pages/PrivacyPolicyPage';
import TermsOfServicePage from './pages/TermsOfServicePage';
import ContactPage from './pages/ContactPage';
import PlannerPage from './pages/PlannerPage';
import Navbar from './components/Navbar';
import Footer from './components/Footer';

export type ViewType = 'home' | 'how-it-works' | 'features' | 'pricing' | 'blog' | 'guidebooks' | 'community' | 'support' | 'about' | 'privacy' | 'terms' | 'contact' | 'planner';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('home');
  const [isDark, setIsDark] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    const savedTheme = localStorage.getItem('theme');
    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
    if (savedTheme === 'dark' || (!savedTheme && prefersDark)) {
      setIsDark(true);
      document.documentElement.classList.add('dark');
    }
  }, []);

  const toggleTheme = () => {
    const newMode = !isDark;
    setIsDark(newMode);
    if (newMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  };

  const navigateTo = (newView: ViewType, query: string = '') => {
    setSearchQuery(query);
    setView(newView);
    window.scrollTo(0, 0);
  };

  const renderView = () => {
    switch (view) {
      case 'planner': return <PlannerPage initialQuery={searchQuery} navigateTo={navigateTo} />;
      case 'how-it-works': return <HowItWorksPage />;
      case 'features': return <FeaturesPage />;
      case 'pricing': return <PricingPage />;
      case 'blog': return <BlogPage />;
      case 'guidebooks': return <GuidebooksPage />;
      case 'community': return <CommunityPage />;
      case 'support': return <SupportPage />;
      case 'about': return <AboutPage />;
      case 'privacy': return <PrivacyPolicyPage />;
      case 'terms': return <TermsOfServicePage />;
      case 'contact': return <ContactPage navigateTo={navigateTo} />;
      case 'home':
      default:
        return <LandingPage navigateTo={navigateTo} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-white dark:bg-slate-950 transition-colors duration-300">
      <Navbar isDark={isDark} toggleTheme={toggleTheme} navigateTo={navigateTo} currentView={view} />
      <main className="flex-grow">
        {renderView()}
      </main>
      <Footer navigateTo={navigateTo} />
    </div>
  );
};

export default App;

